// ── backtestData.js ────────────────────────────────────────
// Fetches historical monthly price data for backtesting.

const API_KEY  = process.env.REACT_APP_FMP_KEY;
const BASE_URL = "https://financialmodelingprep.com/api/v3";

const historyCache = {};

// ── Fetch monthly closing prices for one ticker ────────────
export async function fetchMonthlyPrices(ticker, years = 5) {
  if (historyCache[ticker]) return historyCache[ticker];

  const to   = new Date();
  const from = new Date();
  from.setFullYear(from.getFullYear() - years);
  const fromStr = from.toISOString().slice(0, 10);
  const toStr   = to.toISOString().slice(0, 10);

  const url = `${BASE_URL}/historical-price-full/${ticker}?from=${fromStr}&to=${toStr}&apikey=${API_KEY}`;
  console.log(`Fetching ${ticker}:`, url);

  const res  = await fetch(url);
  if (!res.ok) throw new Error(`HTTP ${res.status} for ${ticker}`);
  const data = await res.json();

  if (data?.["Error Message"]) throw new Error(data["Error Message"]);

  const historical = data?.historical ?? [];
  if (!historical.length) throw new Error(`Empty price history for ${ticker}`);

  // Resample daily → monthly (last trading day per month)
  const sorted = [...historical].reverse(); // oldest first
  const monthly = {};
  sorted.forEach(d => {
    const key = d.date.slice(0, 7);
    monthly[key] = d.adjClose ?? d.close;
  });

  const result = Object.entries(monthly)
    .filter(([, c]) => c != null)
    .map(([date, close]) => ({ date, close }))
    .sort((a, b) => a.date.localeCompare(b.date));

  if (result.length < 6) throw new Error(`Only ${result.length} months for ${ticker}`);

  historyCache[ticker] = result;
  return result;
}

// ── Batch fetch tickers + SPY benchmark ───────────────────
export async function fetchBacktestData(tickers, years = 5) {
  const allTickers = [...new Set([...tickers, "SPY"])];

  const results = await Promise.allSettled(
    allTickers.map(t => fetchMonthlyPrices(t, years))
  );

  const prices = {};
  const errors = [];

  allTickers.forEach((ticker, i) => {
    if (results[i].status === "fulfilled") {
      prices[ticker] = results[i].value;
    } else {
      console.warn(`Skipping ${ticker}:`, results[i].reason?.message);
      errors.push(ticker);
    }
  });

  const benchmark = prices["SPY"] ?? [];
  delete prices["SPY"];

  return { prices, benchmark, errors };
}
